void HAL_TIM_PeriodElapsedCallback(TIM_HandleTypeDef *htim)
{
    if (htim->Instance == TIM6)
    {
        encoder_count = (int32_t)__HAL_TIM_GET_COUNTER(&htim4);
        diff = encoder_count - prev_count;

        // Handle overflow
        if (diff > 32767)
            diff -= 65536;
        else if (diff < -32767)
            diff += 65536;

        prev_count = encoder_count;
        actualpos += diff;

        if(runSequence && atPosFlag)
            Sequence_Update();

        if(runSequence && holdStartTime == 0 && tickMs >= currentStep(&seq1)->fire_time_ms)
        	HAL_GPIO_WritePin(GPIOB, LED_Pin, GPIO_PIN_SET);
        else if(runSequence)
        	HAL_GPIO_WritePin(GPIOB, LED_Pin, GPIO_PIN_RESET);

        commandpos = update_Command_Position(&command1);

        Verify_At_Position();

        if(!atPosFlag){
            duty = PID_Update(&pid1, commandpos, actualpos);
        	if (duty > 0)
        		Motor_Forward((uint16_t)duty);
        	else if (duty < 0)
        		Motor_Reverse((uint16_t)(-duty));
        	else
        		Motor_Brake();
        }
    }

    if (htim->Instance == TIM7)
        {

            tickMs++;
            if(fireSol){
            	if(tickMs == 100)
            		Fire_Solenoids(testSols);
            	if(tickMs >= (100+solDelay))
            		Retract_Solenoids(testSols);
            	if(tickMs >= 2000)
            		tickMs = 0;
            }

        }
}


